/**
 * Singleton implementation of a Map to store cron data across the process
 * @example
 * const cronStorage = require('./storage');
 * await cronStorage.set('key', 'value');
 * const value = await cronStorage.get('key');
 */
class CronDataStorage {
  constructor() {
    /** @private */
    this.storage = new Map();
  }

  /**
   * @public
   * @param {string} key
   * @param {any} value
   */
  async set(key, value) {
    if (typeof key === 'string' && key.trim()) {
      await Promise.resolve(this.storage.set(key, value));
    }
  }

  /**
   * @public
   * @template T
   * @param {string} key
   * @returns {Promise<T>}
   */
  async get(key) {
    return Promise.resolve(this.storage.get(key));
  }

  /**
   * @public
   * @param {string} key
   */
  async delete(key) {
    return Promise.resolve(this.storage.delete(key));
  }

  /**
   * @public
   * @returns {string[]}
   */
  keys() {
    return Array.from(this.storage.keys());
  }
}

module.exports = new CronDataStorage();
